    collection.forEach(function(doc) {
        var projectedDoc = {};
        for (var key in projection) {
            var parts = key.split('.');
            var currentDoc = doc;
            for (var i = 0; i < parts.length; i++) {
                if (currentDoc[parts[i]] !== undefined) {
                    currentDoc = currentDoc[parts[i]];
                } else {
                    break;
                }
            }
            if (currentDoc !== undefined) {
                projectedDoc[key] = currentDoc;
            }
        }
        result.push(projectedDoc);
    });
    return result;
}

