class Solution:
    def projectDocuments(self, collection, projection):
        result = []
        for doc in collection:
            projectedDoc = {}
            for key in projection:
                parts = key.split('.')
                currentDoc = doc
                for i in range(len(parts)):
                    if parts[i] in currentDoc:
                        currentDoc = currentDoc[parts[i]]
                    else:
                        break
                if currentDoc is not None:
                    projectedDoc[key] = currentDoc
            result.append(projectedDoc)
        return result
